const [searchValue, loadCallback, currentDataLength] = e.args;

console.log(e.args);

// ✅ Clear previous debounce timer
if (window._dropdownDebounceTimer) {
    clearTimeout(window._dropdownDebounceTimer);
}

// ✅ Abort previous pending request
if (window._dropdownAbortController) {
    window._dropdownAbortController.abort();
}

// ✅ Create new abort controller for this request
window._dropdownAbortController = new AbortController();
const signal = window._dropdownAbortController.signal;

// ✅ Debounce: Wait 300ms before making API call
window._dropdownDebounceTimer = setTimeout(async () => {

    // Auth Token
    let savedToken = localStorage.getItem('dlms_auth_token');

    // Logic to determine requestBody
    let requestBody = {
        "fields": ["main__data__casting_name","main__data__weight" ],
        "filters": [],
        "search": [],
        "flat": false,
        "status": "completed",
        "limit": 100
    };

    if (searchValue) {
        requestBody = {
            "fields": ["main__data__casting_name","main__data__weight" ],
            "search_fields": ["main__data__casting_name","main__data__weight" ],
            "filters": [],
            "search": [searchValue],
            "flat": false,
            "status": "completed",
            "limit": 20
        };
    }

    try {
        const res = await fetch('https://dlms-api.iotnp.com/api/v1/templates/casting_master/dropdown', {
            method: 'POST',
            headers: {
                'accept': 'application/json',
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${savedToken}`
            },
            body: JSON.stringify(requestBody),
            signal: signal
        });

        const response = await res.json();
        const items = Array.isArray(response.data) ? response.data : [];

        // Filter items based on search value
        const filteredItems = items.filter(item => {
            const name = item.main?.data?.casting_name || "";
            const weight = item.main?.data?.weight || "";
            // return name.toLowerCase().includes((searchValue || "").toLowerCase());
            const search = (searchValue || "").toLowerCase();

            return (
                name.toLowerCase().includes(search) ||
                weight.toString().includes(search)
            );
        });

        // Create unique map to remove duplicates
        const uniqueMap = new Map();
        filteredItems.forEach(item => {
            const castingName = item.main?.data?.casting_name || "Unnamed Item";
            const id = item._id;
            const weight = item.main?.data?.weight ?? "N/A";
            if (!uniqueMap.has(castingName)) {
                uniqueMap.set(castingName, {
                    value: castingName,
                    label: castingName,
                    id: id,
                    weight: weight,
                    data: item
                });
            }
        });

        // Convert map to array and apply pagination
        const preparedData = [...uniqueMap.values()]
            .slice(currentDataLength || 0, (currentDataLength || 0) + 20);

        // SAFETY CHECK: Ensure loadCallback is actually a function before calling it
        if (typeof loadCallback === 'function') {
            loadCallback(preparedData);
        } else {
            console.warn("loadCallback is not a function. Check e.args structure:", e.args);
        }

    } catch (err) {
        // Ignore abort errors (expected when cancelling)
        if (err.name === 'AbortError') {
            console.log('Previous request cancelled');
            return;
        }
        console.error("Dropdown fetch error:", err);
        if (typeof loadCallback === 'function') loadCallback([]);
    }

}, 300);

