const value = formData.serial_no;

  if (!value || value.trim() === '') {
    return undefined;
  }

  const savedToken = localStorage.getItem('dlms_auth_token');
  if (!savedToken) {
    return undefined;
  }

  const serialNumbers = value
    .split(',')
    .map(sn => sn.trim())
    .filter(sn => sn !== '');

  if (serialNumbers.length === 0) {
    return undefined;
  }

  // Check for duplicate entries in user input
  const seen = new Set();
  const duplicatesInInput = [];

  for (const sn of serialNumbers) {
    if (seen.has(sn)) {
      if (!duplicatesInInput.includes(sn)) {
        duplicatesInInput.push(sn);
      }
    } else {
      seen.add(sn);
    }
  }

  if (duplicatesInInput.length > 0) {
    if (duplicatesInInput.length === 1) {
      return { serial_no: `Duplicate serial number entered: "${duplicatesInInput[0]}"` };
    } else {
      return { serial_no: `Duplicate serial numbers entered: ${duplicatesInInput.join(', ')}` };
    }
  }

  // Check all serial numbers in parallel (API validation)
  const checkPromises = serialNumbers.map(async (serialNumber) => {
    try {
      const res = await fetch(`https://dlms-api.iotnp.com/api/v1/serial-numbers/check?serial_number=${encodeURIComponent(serialNumber)}`, {
        method: 'GET',
        headers: {
          'accept': 'application/json',
          'Authorization': `Bearer ${savedToken}`
        }
      });

      const response = await res.json();
      console.log('API Response for', serialNumber, ':', response);

      if (response.exists === true) {
        return {
          serialNumber,
          exists: true,
          templateName: response.template_name
        };
      }

      return { serialNumber, exists: false };
    } catch (err) {
      console.error(`Error checking ${serialNumber}:`, err);
      return { serialNumber, exists: false };
    }
  });

  const results = await Promise.all(checkPromises);
  console.log('All results:', results);

  const duplicates = results.filter(r => r.exists === true);
  console.log('Duplicates found:', duplicates);

  if (duplicates.length > 0) {
    const duplicateSerialNumbers = duplicates.map(d => d.serialNumber);

    let errorMessage;
    if (duplicateSerialNumbers.length === 1) {
      const templateInfo = duplicates[0].templateName ? ` in "${duplicates[0].templateName}"` : '';
      errorMessage = `Serial number "${duplicateSerialNumbers[0]}" already exists${templateInfo}`;
    } else {
      const dupNames = duplicateSerialNumbers.join(', ');
      errorMessage = `Serial numbers already exist: ${dupNames}`;
    }

    console.log('🚨 RETURNING ERROR:', errorMessage);

    return { serial_no: errorMessage };
  }

  console.log('✅ No duplicates, returning undefined');
  return undefined;

