// Initialize debounce state on window if not exists
  if (!window._serialValidation) {
    window._serialValidation = {
      timer: null,
      abortController: null,
      lastValue: null,
      lastResult: true
    };
  }

  const state = window._serialValidation;

  // Early return for empty values
  if (!value || value.trim() === '') {
    return true;
  }

  // If same value as last validated, return cached result
  if (value === state.lastValue && state.lastResult !== null) {
    return state.lastResult;
  }

  // Abort previous request
  if (state.abortController) {
    state.abortController.abort();
  }

  // Create debounced validation
  return new Promise((resolve) => {
    // Clear previous timer
    if (state.timer) {
      clearTimeout(state.timer);
    }

    state.timer = setTimeout(async () => {
      const savedToken = localStorage.getItem('dlms_auth_token');
      if (!savedToken) {
        state.lastValue = value;
        state.lastResult = true;
        resolve(true);
        return;
      }

      const serialNumbers = value
        .split(',')
        .map(sn => sn.trim())
        .filter(sn => sn !== '');

      if (serialNumbers.length === 0) {
        state.lastValue = value;
        state.lastResult = true;
        resolve(true);
        return;
      }

      // Check for duplicate entries in user input
      const seen = new Set();
      for (const sn of serialNumbers) {
        if (seen.has(sn)) {
          state.lastValue = value;
          state.lastResult = false;
          resolve(false);
          return;
        }
        seen.add(sn);
      }

      // API validation
      state.abortController = new AbortController();
      const signal = state.abortController.signal;

      try {
        const checkPromises = serialNumbers.map(async (serialNumber) => {
          try {
            const res = await fetch(
              `https://dlms-api.iotnp.com/api/v1/serial-numbers/check?serial_number=${encodeURIComponent(serialNumber)}`,
              {
                method: 'GET',
                headers: {
                  'accept': 'application/json',
                  'Authorization': `Bearer ${savedToken}`
                },
                signal
              }
            );
            const response = await res.json();
            return response.exists === true;
          } catch (err) {
            if (err.name === 'AbortError') throw err;
            return false;
          }
        });

        const results = await Promise.all(checkPromises);
        const hasDuplicate = results.some(exists => exists === true);

        state.lastValue = value;
        state.lastResult = !hasDuplicate;
        resolve(!hasDuplicate);
      } catch (err) {
        if (err.name === 'AbortError') {
          // Don't resolve - new request will handle it
          return;
        }
        state.lastValue = value;
        state.lastResult = true;
        resolve(true);
      }
    }, 300); // 300ms debounce
  });
